from sympy import solve , Eq, symbols

x, y = symbols("x y")

Ecuation1= Eq(4*x-2*y, 6)
Ecuation2= Eq(9*x+7*y, 48)

solution = solve((Ecuation1,Ecuation2), (x, y))

print("The solution of the first system it is: ")
print("x =", solution [x])
print("y = ",solution [y])

Ecuation3 = Eq(-x+8*y, 20)
Ecuation4 = Eq(5*x-2*y, -24)

solution2 = solve((Ecuation3,Ecuation4),(x,y))

print("The solution of the second system it is:")
print("x = ", solution2[x])
print("y = ", solution2[y])

Ecuation5 = Eq(8*x-2*y,-46)
Ecuation6 = Eq(3*x-4*y, 12)

solution3 = solve((Ecuation5,Ecuation6), (x,y))

print ("The result of the system three it is : ")
print("x =", solution3[x])
print("y =", solution3[y])

Ecuation7 = Eq(-2*x-2*y, 14)
Ecuation8 = Eq(-4*x+2*y, 10)

solution4 = solve((Ecuation7,Ecuation8), (x,y))

print("The solution of the fourth systme it is: ")
print("X = ", solution4[x])
print("y =", solution4[y])

Ecuation9 = (2*x-4*y, -18)
Ecuation10 =(2*x-2*y, -10)

solution5 = solve((Ecuation9, Ecuation10),(x,y))

print("The result of the fifth system it is: ")
print("x = ", solution5[x])
print("y = ", solution5[y])